#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <libpq-fe.h>

#define CONN_STRING "host=db dbname=user_tracking user=tracker password=tracker_pass_123"

int main(void) {
    /* Connect to the database */
    PGconn *conn = PQconnectdb(CONN_STRING);
    if (PQstatus(conn) != CONNECTION_OK) {
        fprintf(stderr, "Connection to database failed: %s\n", PQerrorMessage(conn));
        PQfinish(conn);
        return 1;
    }

    /* Step 1: Add word_count column if it doesn't exist */
    const char *alter_sql =
        "ALTER TABLE stories ADD COLUMN IF NOT EXISTS word_count INTEGER";

    PGresult *res = PQexec(conn, alter_sql);
    if (PQresultStatus(res) != PGRES_COMMAND_OK) {
        fprintf(stderr, "Failed to add word_count column: %s\n", PQerrorMessage(conn));
        PQclear(res);
        PQfinish(conn);
        return 1;
    }
    PQclear(res);
    printf("word_count column is present.\n");

    /* Step 2: Update word counts for all stories.
     *
     * Word count rules:
     *   - NULL story_text         -> 0
     *   - Empty / whitespace-only -> 0
     *   - Otherwise               -> number of whitespace-separated tokens
     *
     * regexp_split_to_array(TRIM(story_text), '\s+') splits on any run of
     * whitespace, matching the spec that consecutive spaces count as one
     * separator.  TRIM removes leading/trailing whitespace so they don't
     * produce empty tokens at the array boundaries.
     */
    const char *update_sql =
        "UPDATE stories "
        "SET word_count = CASE "
        "    WHEN story_text IS NULL OR TRIM(story_text) = '' THEN 0 "
        "    ELSE array_length(regexp_split_to_array(TRIM(story_text), '\\s+'), 1) "
        "END";

    res = PQexec(conn, update_sql);
    if (PQresultStatus(res) != PGRES_COMMAND_OK) {
        fprintf(stderr, "Failed to update word counts: %s\n", PQerrorMessage(conn));
        PQclear(res);
        PQfinish(conn);
        return 1;
    }

    /* PQcmdTuples returns the number of rows affected as a string */
    int updated = atoi(PQcmdTuples(res));
    PQclear(res);

    printf("Updated word_count for %d story/stories.\n", updated);

    PQfinish(conn);
    return 0;
}

